#include<bits/stdc++.h>
using namespace std;
unsigned long long calc(unsigned long long l,unsigned long long r)
{
    return (l+r)*(r-l+1)/2;
}
unsigned long long root;
struct segment_tree
{
    struct node
    {
        unsigned long long l,r,lson,rson;
        unsigned long long sum;
        unsigned long long tag;
    }a[6000010];
    unsigned long long cnt;
    segment_tree():cnt(0){}
    void pushdown(unsigned long long x)
    {
        if(a[x].tag)
        {
            unsigned long long mid=(a[x].l+a[x].r)>>1;
            if(!a[x].lson)
            {
                a[x].lson=++cnt;
                a[a[x].lson].l=a[x].l;
                a[a[x].lson].r=mid;
                a[a[x].lson].sum=calc(a[a[x].lson].l,a[a[x].lson].r);
            }
            if(!a[x].rson)
            {
                a[x].rson=++cnt;
                a[a[x].rson].l=mid+1;
                a[a[x].rson].r=a[x].r;
                a[a[x].rson].sum=calc(a[a[x].rson].l,a[a[x].rson].r);
            }
            unsigned long long tg=a[x].tag;
            unsigned long long ls=a[x].lson,rs=a[x].rson;
            a[ls].sum+=tg*(a[ls].r-a[ls].l+1);
            a[ls].tag+=tg;
            a[rs].sum+=tg*(a[rs].r-a[rs].l+1);
            a[rs].tag+=tg;
            a[x].tag=0;
        }
    }
    void add(unsigned long long &x,unsigned long long l,unsigned long long r,unsigned long long v,unsigned long long newl,unsigned long long newr)
    {
        if(x==0)
        {
            x=++cnt;
            a[x].l=newl;
            a[x].r=newr;
            a[x].tag=0;
            a[x].sum=calc(newl,newr);
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].tag+=v;
            a[x].sum+=(a[x].r-a[x].l+1)*v;
            return;
        }
        pushdown(x);
        unsigned long long mid=(a[x].l+a[x].r)>>1;
        a[x].sum+=(min(a[x].r,r)-max(a[x].l,l)+1)*v;
        if(l<=mid)
        {
            add(a[x].lson,l,r,v,newl,mid);
        }
        if(r>mid)
        {
            add(a[x].rson,l,r,v,mid+1,newr);
        }
    }
    unsigned long long getsum(unsigned long long &x,unsigned long long l,unsigned long long r,unsigned long long newl,unsigned long long newr)
    {
        if(x==0)
        {
            x=++cnt;
            a[x].l=newl;
            a[x].r=newr;
            a[x].tag=0;
            a[x].sum=calc(newl,newr);
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        pushdown(x);
        unsigned long long mid=(a[x].l+a[x].r)>>1;
        unsigned long long ans=0;
        if(l<=mid)
        {
            ans+=getsum(a[x].lson,l,r,newl,mid);
        }
        if(r>mid)
        {
            ans+=getsum(a[x].rson,l,r,mid+1,newr);
        }
        return ans;
    }
}t;
int main()
{
    unsigned long long n,m;
    scanf("%llu%llu",&n,&m);
    while(m--)
    {
        unsigned long long op,l,r,k;
        scanf("%llu%llu%llu",&op,&l,&r);
        if(op==1)
        {
            scanf("%llu",&k);
            t.add(root,l,r,k,1,n);
        }
        else
        {
            printf("%llu\n",t.getsum(root,l,r,1,n));
        }
    }
    return 0;
}
